// LoginActivity.kt
package com.example.auth

import android.content.Intent
import android.os.Bundle
import android.widget.Button
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import java.util.concurrent.Executor

class LoginActivity : AppCompatActivity() {

    private lateinit var executor: Executor
    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login)

        executor = ContextCompat.getMainExecutor(this)
        biometricPrompt = BiometricPrompt(this, executor, callback)

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Fingerprint login")
            .setSubtitle("Authenticate with your fingerprint")
            .setNegativeButtonText("Use password")
            .build()

        findViewById<Button>(R.id.fingerprintButton).setOnClickListener { launchBiometric() }

        launchBiometric()
    }

    private fun launchBiometric() {
        when (BiometricManager.from(this)
            .canAuthenticate(
                BiometricManager.Authenticators.BIOMETRIC_STRONG
                        or BiometricManager.Authenticators.DEVICE_CREDENTIAL
            )
        ) {
            BiometricManager.BIOMETRIC_SUCCESS -> biometricPrompt.authenticate(promptInfo)
            else -> showPasswordDialog()
        }
    }

    private val callback = object : BiometricPrompt.AuthenticationCallback() {
        override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
            super.onAuthenticationSucceeded(result)
            onAuthenticated()
        }

        override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
            super.onAuthenticationError(errorCode, errString)
            if (errorCode == BiometricPrompt.ERROR_NEGATIVE_BUTTON) showPasswordDialog()
        }
    }

    private fun onAuthenticated() {
        AuthManager.setAuthenticated(this, true)
        startActivity(Intent(this, MainActivity::class.java))
        finish()
    }

    private fun showPasswordDialog() {
        PasswordDialogFragment { pass ->
            if (checkPassword(pass)) {
                onAuthenticated()
            } else {
                Toast.makeText(this, "Incorrect password", Toast.LENGTH_SHORT).show()
            }
        }.show(supportFragmentManager, "pwd")
    }

    private fun checkPassword(password: String) = password == "1234" // Replace in production
}



// PasswordDialogFragment.kt
package com.example.auth

import android.app.Dialog
import android.os.Bundle
import android.view.LayoutInflater
import android.widget.EditText
import androidx.appcompat.app.AlertDialog
import androidx.fragment.app.DialogFragment

class PasswordDialogFragment(
    private val onResult: (String) -> Unit
) : DialogFragment() {

    override fun onCreateDialog(savedInstanceState: Bundle?): Dialog {
        val view = LayoutInflater.from(requireContext())
            .inflate(R.layout.dialog_password, null)
        val input = view.findViewById<EditText>(R.id.passwordInput)

        return AlertDialog.Builder(requireContext())
            .setTitle("Enter password")
            .setView(view)
            .setPositiveButton("OK") { _, _ -> onResult(input.text.toString()) }
            .setNegativeButton("Cancel", null)
            .create()
    }
}



// MainActivity.kt
package com.example.auth

import android.content.Intent
import android.os.Bundle
import android.widget.Button
import androidx.appcompat.app.AppCompatActivity

class MainActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        findViewById<Button>(R.id.logoutButton).setOnClickListener {
            AuthManager.clear(this)
            startActivity(Intent(this, LoginActivity::class.java))
            finish()
        }
    }
}